proof fn phi_5_no_two_distinct_keys<K: KeyTrait + VerusClone>(map: StrictlyOrderedMap<K>, k1: K, k2: K, i1: usize, i2: usize)
    requires
        map.valid(),
        0 <= i1 < map.keys@.len(),
        0 <= i2 < map.keys@.len(),
        map.keys@[i1 as int] == k1,
